/* The Moon's AUGMENTED semidiameter vs the USNO celnav service
 * (aa.usno.navy.mil/data/celnav, transcribed 2026-07): the SD
 * its altitude_corrections block prints is the topocentric one
 * the observer applies. Altitude 10..90 deg at the 2026-12-24
 * perigee (HP 61.5') and 2026-12-11 apogee (HP 54.0') plus one
 * mid-range row; the check holds our geocentric SD plus
 * astro_nav_moon_augmentation_marcmin() against it. See the
 * generator for why the service's refr/pa are not comparable
 * at Hc and are left ungated. */
typedef struct {
    int64_t ut1_ms;          /* UT1 ms since J2000.0 */
    int32_t tt_minus_ut1_ms;
    int32_t hc_marcmin;      /* USNO Hc, the augmentation's h */
    int32_t sd_topo_marcmin; /* USNO printed (augmented) SD */
} ext_usno_moon_row_t;

